sql:
SELECT u.user_name, p.portfolio_name
FROM users u
INNER JOIN portfolios p ON u.user_id = p.user_id;

SELECT close_price
FROM daily_prices
WHERE stock_id = 1 AND date = '2023-10-01';

external_knowledge:
- 'wild waves of the sea' metaphorically represents highly volatile stocks;
- 'intensity' refers to the beta value, a measure of stock volatility relative to the market;
- 'daily mood swings' represent daily percentage price changes, indicative of volatility and market reaction;
- more than 'a hundred days' ensures a significant period for analysis.

sql:
SELECT SUM(total_value) AS total_portfolio_value
FROM portfolios
WHERE user_id = 1;

external_knowledge:
- "gardeners" metaphorically refers to the users;
- "golden seeds" metaphorically refers to the shares or holdings in their portfolios;
- "harvest" metaphorically refers to the total portfolio value.

sql:
SELECT AVG(change_percent) AS average_price_change
FROM daily_prices
WHERE date BETWEEN '2023-01-01' AND '2023-10-01';

SELECT time_zone
FROM user_preferences
WHERE user_id = 1;

SELECT AVG(dp.close_price) AS average_close_price
FROM daily_prices dp
WHERE dp.date BETWEEN DATE('now','-30 days') AND DATE('now');

SELECT COUNT(alert_id) AS total_alerts
FROM alerts
WHERE user_id = 0;

SELECT company_name
FROM stocks
WHERE market_cap = (SELECT MAX(market_cap) FROM stocks);

SELECT symbol, company_name 
FROM stocks 
WHERE price_earnings_ratio > 20;

SELECT SUM(market_cap) AS total_market_cap 
FROM stocks 
WHERE sector = 'Technology';

SELECT MAX(high_price) AS highest_high_price
FROM daily_prices
WHERE date = '2023-10-01';

SELECT SUM(total_value) AS total_portfolio_value
FROM portfolios
WHERE user_id = 1;

SELECT COUNT(*) AS market_news_subscribers
FROM user_preferences
WHERE market_news_subscription = 1;
